# 构建聊天组件并爬取掘金文章

在这篇文章中，我将详细介绍如何使用 Next.js 构建一个实时聊天组件，并实现掘金文章的爬取功能。这个实现包括前端界面、后端 API 以及数据爬取的完整流程。

## 聊天组件实现

### 1. 创建聊天组件

首先，我们在 `src/app/chat` 目录下创建聊天组件：

```tsx
// src/app/chat/page.tsx
'use client'

import { useState } from 'react'
import { useChat } from '@/hooks/useChat'
import { ChatMessage } from '@/components/ChatMessage'
import { ChatInput } from '@/components/ChatInput'

export default function ChatPage() {
  const [messages, setMessages] = useState([])
  const { sendMessage, isLoading } = useChat()

  const handleSend = async (content: string) => {
    // 添加用户消息
    const userMessage = {
      role: 'user',
      content,
      id: Date.now()
    }
    setMessages(prev => [...prev, userMessage])

    // 发送消息并获取回复
    const response = await sendMessage(content)

    // 添加助手回复
    const assistantMessage = {
      role: 'assistant',
      content: response.message,
      id: Date.now() + 1
    }
    setMessages(prev => [...prev, assistantMessage])
  }

  return (
    <div className="flex flex-col h-screen">
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map(message => (
          <ChatMessage
            key={message.id}
            role={message.role}
            content={message.content}
          />
        ))}
      </div>
      <div className="border-t p-4">
        <ChatInput onSend={handleSend} isLoading={isLoading} />
      </div>
    </div>
  )
}
```

### 2. 创建聊天消息组件

```tsx
// src/components/ChatMessage.tsx
interface ChatMessageProps {
  role: 'user' | 'assistant'
  content: string
}

export function ChatMessage({ role, content }: ChatMessageProps) {
  const isUser = role === 'user'

  return (
    <div className={`flex ${isUser ? 'justify-end' : 'justify-start'}`}>
      <div
        className={`max-w-[80%] rounded-lg p-4 ${
          isUser
            ? 'bg-blue-500 text-white'
            : 'bg-gray-100 text-gray-800'
        }`}
      >
        {content}
      </div>
    </div>
  )
}
```

### 3. 创建聊天输入组件

```tsx
// src/components/ChatInput.tsx
interface ChatInputProps {
  onSend: (message: string) => void
  isLoading: boolean
}

export function ChatInput({ onSend, isLoading }: ChatInputProps) {
  const [message, setMessage] = useState('')

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!message.trim() || isLoading) return

    onSend(message)
    setMessage('')
  }

  return (
    <form onSubmit={handleSubmit} className="flex gap-2">
      <input
        type="text"
        value={message}
        onChange={(e) => setMessage(e.target.value)}
        placeholder="输入消息..."
        className="flex-1 rounded-lg border p-2"
        disabled={isLoading}
      />
      <button
        type="submit"
        disabled={isLoading}
        className="rounded-lg bg-blue-500 px-4 py-2 text-white disabled:opacity-50"
      >
        发送
      </button>
    </form>
  )
}
```

### 4. 创建聊天 Hook

```tsx
// src/hooks/useChat.ts
import { useState } from 'react'

export function useChat() {
  const [isLoading, setIsLoading] = useState(false)

  const sendMessage = async (message: string) => {
    setIsLoading(true)
    try {
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ message }),
      })

      const data = await response.json()
      return data
    } catch (error) {
      console.error('发送消息失败:', error)
      throw error
    } finally {
      setIsLoading(false)
    }
  }

  return { sendMessage, isLoading }
}
```

## 后端 API 实现

### 1. 创建聊天 API 路由

```typescript
// src/app/api/chat/route.ts
import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'

export async function POST(request: NextRequest) {
  try {
    const { message } = await request.json()

    // 这里可以添加你的消息处理逻辑
    // 例如：调用 AI API、处理特定命令等

    const response = {
      message: `收到你的消息：${message}`,
      timestamp: new Date().toISOString(),
    }

    return NextResponse.json(response)
  } catch (error) {
    return NextResponse.json(
      { error: '处理消息失败' },
      { status: 500 }
    )
  }
}
```

## 掘金文章爬取实现

### 1. 创建爬虫 API 路由

```typescript
// src/app/api/juejin/route.ts
import { NextResponse } from 'next/server'
import type { NextRequest } from 'next/server'
import * as cheerio from 'cheerio'

export async function GET(request: NextRequest) {
  try {
    // 获取查询参数
    const searchParams = request.nextUrl.searchParams
    const tag = searchParams.get('tag') || ''
    const page = parseInt(searchParams.get('page') || '1')

    // 构建掘金 API URL
    const url = `https://juejin.cn/tag/${encodeURIComponent(tag)}`

    // 发送请求获取页面内容
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36'
      }
    })

    const html = await response.text()

    // 使用 cheerio 解析 HTML
    const $ = cheerio.load(html)

    // 提取文章信息
    const articles = []
    $('.article-item').each((i, element) => {
      const title = $(element).find('.title').text().trim()
      const link = $(element).find('.title a').attr('href')
      const author = $(element).find('.author').text().trim()
      const description = $(element).find('.description').text().trim()

      articles.push({
        title,
        link: `https://juejin.cn${link}`,
        author,
        description
      })
    })

    return NextResponse.json({
      articles,
      page,
      tag
    })
  } catch (error) {
    console.error('爬取掘金文章失败:', error)
    return NextResponse.json(
      { error: '爬取文章失败' },
      { status: 500 }
    )
  }
}
```

### 2. 创建文章列表组件

```tsx
// src/components/ArticleList.tsx
interface Article {
  title: string
  link: string
  author: string
  description: string
}

interface ArticleListProps {
  articles: Article[]
  isLoading: boolean
}

export function ArticleList({ articles, isLoading }: ArticleListProps) {
  if (isLoading) {
    return <div>加载中...</div>
  }

  return (
    <div className="space-y-4">
      {articles.map((article, index) => (
        <article key={index} className="border rounded-lg p-4">
          <h2 className="text-xl font-bold">
            <a
              href={article.link}
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-500 hover:underline"
            >
              {article.title}
            </a>
          </h2>
          <p className="text-gray-600 mt-1">作者：{article.author}</p>
          <p className="text-gray-700 mt-2">{article.description}</p>
        </article>
      ))}
    </div>
  )
}
```

### 3. 创建文章获取 Hook

```typescript
// src/hooks/useArticles.ts
import { useState, useEffect } from 'react'

export function useArticles(tag: string) {
  const [articles, setArticles] = useState([])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)

  const fetchArticles = async (page = 1) => {
    setIsLoading(true)
    setError(null)

    try {
      const response = await fetch(
        `/api/juejin?tag=${encodeURIComponent(tag)}&page=${page}`
      )
      const data = await response.json()

      if (!response.ok) throw new Error(data.error)

      setArticles(data.articles)
    } catch (err) {
      setError(err.message)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    if (tag) {
      fetchArticles()
    }
  }, [tag])

  return { articles, isLoading, error, fetchArticles }
}
```

## 组件整合使用

现在我们可以在页面中组合使用这些组件：

```tsx
// src/app/page.tsx
'use client'

import { useState } from 'react'
import { ChatComponent } from '@/components/Chat'
import { ArticleList } from '@/components/ArticleList'
import { useArticles } from '@/hooks/useArticles'

export default function HomePage() {
  const [tag, setTag] = useState('前端')
  const { articles, isLoading, fetchArticles } = useArticles(tag)

  const handleChatMessage = async (message: string) => {
    if (message.startsWith('/search ')) {
      const newTag = message.slice(8)
      setTag(newTag)
      await fetchArticles()
    }
  }

  return (
    <div className="flex h-screen">
      <div className="w-1/2 border-r">
        <ChatComponent onMessage={handleChatMessage} />
      </div>
      <div className="w-1/2 p-4">
        <h1 className="text-2xl font-bold mb-4">掘金文章</h1>
        <ArticleList articles={articles} isLoading={isLoading} />
      </div>
    </div>
  )
}
```

## 注意事项

1. 爬虫限制：
   - 注意遵守掘金的爬虫政策
   - 添加适当的请求延迟
   - 使用合适的 User-Agent
   - 考虑使用官方 API（如果有）

2. 性能优化：
   - 实现文章缓存
   - 添加分页加载
   - 使用虚拟滚动处理大量文章

3. 错误处理：
   - 添加适当的错误边界
   - 实现重试机制
   - 提供用户友好的错误提示

4. 安全考虑：
   - 添加速率限制
   - 验证用户输入
   - 防止 XSS 攻击

